class Solution {
    public int[] popcountDepth(long[] nums, long[][] queries) {
        int n = nums.length;
        int q = queries.length;

        int[] depth = new int[n];
        for (int i = 0; i < n; i++) {
            depth[i] = getDepth(nums[i]);
        }

        int[][] fenwick = new int[6][n + 2];
        for (int k = 0; k <= 5; k++) {
            for (int i = 0; i < n; i++) {
                if (depth[i] == k) {
                    update(fenwick[k], i + 1, 1);
                }
            }
        }

        List<Integer> res = new ArrayList<>();
        for (long[] query : queries) {
            if (query[0] == 1) {
                int l = (int) query[1];
                int r = (int) query[2];
                int k = (int) query[3];
                if (k < 0 || k > 5) {
                    res.add(0);
                } else {
                    int cnt = query(fenwick[k], r + 1) - query(fenwick[k], l);
                    res.add(cnt);
                }
            } else {
                int idx = (int) query[1];
                long val = query[2];
                int newDepth = getDepth(val);
                int oldDepth = depth[idx];
                if (oldDepth != newDepth) {
                    update(fenwick[oldDepth], idx + 1, -1);
                    update(fenwick[newDepth], idx + 1, 1);
                    depth[idx] = newDepth;
                }
            }
        }

        int[] ans = new int[res.size()];
        for (int i = 0; i < res.size(); i++) {
            ans[i] = res.get(i);
        }
        return ans;
    }

    private int getDepth(long x) {
        int d = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            d++;
        }
        return d;
    }

    private void update(int[] fenwick, int idx, int delta) {
        while (idx < fenwick.length) {
            fenwick[idx] += delta;
            idx += idx & -idx;
        }
    }

    private int query(int[] fenwick, int idx) {
        int sum = 0;
        while (idx > 0) {
            sum += fenwick[idx];
            idx -= idx & -idx;
        }
        return sum;
    }
}
